#!/usr/bin/env python3
import os, sys, tarfile, zipfile, gzip, bz2, shutil, argparse
from datetime import date


def main():
    parser = argparse.ArgumentParser(description='Backup user directories')

    parser.add_argument('directory', help='Directory to backup')
    parser.add_argument('-f', '--format', default='tar.gz', choices=['tar.gz','tar.bz2','zip'], help='Compression format (default: tar.gz)')
    parser.add_argument('--verbose', action='store_true', help='Verbose mode')

    args = parser.parse_args()

    if not os.path.isdir(args.directory):
        print('ERROR: Directory does not exist.')
        sys.exit(1)

    backup_dir = os.path.join('/tmp','backup')
    backup_file = '{}-{}.{}'.format(os.path.basename(args.directory), date.today().strftime('%Y%m%d'), args.format[:-3])

    if not os.path.isdir(backup_dir):
        os.mkdir(backup_dir)

    try:
        shutil.make_archive(backup_file, args.format, args.directory)
    except Exception as e:
        print('ERROR: {}'.format(e))
        sys.exit(1)

    if not args.verbose:
        print('Backup created in {}'.format(os.path.join('/tmp','backup')))


if __name__ == '__main__':
    main()